var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"알비온 2호 봉쇄좌표에 도착하였습니다.","JPN":"アルビオン2号、封鎖座標に到着しました。","ENG":"Albion No. 2 has arrived at the sealing coordinates.","TWN":"阿爾比恩2號已到達封鎖座標。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"3호와 4호 5호까지 순차적으로 차원 도약할 겁니다.","JPN":"3号、4号、5号まで順次に次元跳躍します。","ENG":"No. 3, 4, and 5 will take turns in dimension jumping.","TWN":"3號，4號和5號，將依次進行次元躍遷。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"좌표를 수신하자 마자, 즉시 편대를 꾸려 대응하였는데도 이렇게 늦어버리다니.","JPN":"座標を受信するやいなや部隊を編成して対応したのに、こんなに遅れてしまうだなんて。","ENG":"We gathered some ships as soon as we received the coordinates, and still we are late.","TWN":"一收到座標，就立即組織隊伍應對，但還是晚了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇다면 이 좌표를 전달해준 요원은 이미…….","JPN":"おそらく、この座標を送信したエージェントは既に……","ENG":"Then the agent who sent the coordinates must've already...","TWN":"那麼傳達這個座標的特工已經……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"큭! 알비온 3호로부터 송신!","JPN":"くっ！　アルビオン3号からの送信です！","ENG":"Kgh! Message from Albion No. 3!","TWN":"咳！阿爾比恩3號發來了訊號！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L13_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"차원 도약 중에 거대 촉수에 의해 공격받고 있다고 합니다!","JPN":"次元跳躍中、巨大触手の攻撃を受けているとのことです！","ENG":"They are being attacked by giant tentacles in the middle of dimension-jumping!","TWN":"說是次元躍遷時受到了巨大觸手的攻擊！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"기관장님, 서두르셔야 합니다!","JPN":"機関長、お急ぎください！","ENG":"Chief, you have to hurry!","TWN":"機關長，我們得抓緊時間！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"알고있어요.","JPN":"わかっていますわ。","ENG":"I'm aware.","TWN":"我知道。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금의 저는 망설이는 것조차 허락되지 않겠죠.","JPN":"今の私には、迷うことすら許されないでしょうね。","ENG":"I'm not allowed even a second of hesitation right now.","TWN":"現在的我連一秒鐘的猶豫時間都不允許。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"다들 정신 바짝 차리도록 해!","JPN":"皆、しっかりしろ！","ENG":"Look alive, everyone!","TWN":"大家要打起萬分精神！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 이 세계는 어떤 일이 벌어져도 이상하지 않은 마경이다!","JPN":"今この世界は何が起きてもおかしくない魔境となっている！","ENG":"We are in a hellscape where anything can happen!","TWN":"這個煉獄一樣的世界，無論發生什麼事都不奇怪！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관장 엘리자베스 팬드래건이 현장의 모든 기관원들에게 전파합니다.","JPN":"機関長エリザベス・ペンドラゴンが、現場の全機関員に伝えます。","ENG":"Chief Elizabeth Pendragon, alerting all Institution members out on the field.","TWN":"我是機關長，伊莉莎白·潘德拉貢，現場所有人員聽著。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_1"},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"현시간부로 기관은 적성 개체를 마왕 가아그셰블라에 준하는 최고 위험 등급으로 판단.","JPN":"現時刻をもって、機関は敵性個体を魔王ガアグシェブラに準ずる最高位の危険レベルと判断。","ENG":"As of now, the Institution deems the hostile the highest level of danger, no less than that of the Demon Lord Gha'agsheblah.","TWN":"此刻開始，機關將敵人個體判定為相當於魔王加格舍夫拉的最高危險等級。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_2"},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"적성 개체가 현실로 부상하는 것을 저지하기 위해.","JPN":"敵性個体が現実へと浮上することを阻止するために。","ENG":"In order to stop the hostile from emerging in the Normalside...","TWN":"為阻止敵人個體對現世造成傷害，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_3"},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"총력전 체제에 돌입합니다.","JPN":"総力戦体制に突入します。","ENG":"We are entering an all-out war.","TWN":"我們將動員所有人力，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_4"},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이에 따라 현장의 모든 기관원들은 즉시 테크 레벨 4 이상의 장비를 휴대한 뒤.","JPN":"よって、現場の全機関員は直ちにテックレベル4以上の装備を携帯し、","ENG":"Accordingly, all Institution members are to immediately carry gear higher than Tech Level 4 and–","TWN":"請所有人員立刻攜帶技術等級4以上的裝備…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_5"},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"하나가 되어주세요.","JPN":"一つになってください。","ENG":"Become one.","TWN":"合而為一。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_6","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_6_2"},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"반복합니다. 현장의 모든 기관원은 즉시.","JPN":"繰り返します。現場の全機関員はただちに。","ENG":"I repeat. All Institution members out on the field are to–","TWN":"再重複一次，現場所有人員立刻…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_7"},{"id":"L36_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"무의미한 저항을 멈추고 모두 저와 하나가 되는 거예요.","JPN":"無意味な抵抗をやめ、全員私と一つになるのです。","ENG":"Stop your pointless resistance and become one with me.","TWN":"停止無謂的抵抗，並和我合而為一。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_8","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_8_2"},{"id":"L41_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"흐흐, 흐하하하하하하하하하하하하핫……!!","JPN":"ふふ、ふははははははははは……！！","ENG":"Hehe, hehahahahAHAHAHAHA...!!","TWN":"呵呵，哈哈哈哈哈哈哈哈哈……！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"이런 젠장!! 이 개자식아!! 아군을 쏘면 어떡해!!","JPN":"おい、このくそ野郎！！　味方を撃ってどうする！！","ENG":"Dammit!! You bastard!! You just shot an ally!!","TWN":"該死！！你這個混蛋！！你開槍打的是我們人！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ff3636>하, 하하하……! 하나가…… 하나가 되어야만 해……!!</color>","JPN":"<color=#ff3636>は、はひひひ……！　ひとつに……一つにならないと……！！</color>","ENG":"<color=#ff3636>Ha, hahaha...! We must... become one...!!</color>","TWN":"<color=#ff3636>哈哈哈……！必須……必須合而為一……！！</color>"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"전 중대원! 즉시 정보 오염 필터 레벨을 최대치까지 올려!","JPN":"全中隊員！　即時に情報汚染フィルターのレベルを最大まで上げろ！","ENG":"All soldiers! Raise your data corruption filter levels to the maximum! Now!","TWN":"全體中隊隊員！立即將資訊污染過濾等級提高到最大值！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터가 아닌 인간이 맨눈으로 개체를 관측하거나, 속삭임을 들으면 미쳐버린다!","JPN":"カウンターじゃない人間が裸眼で個体を観測したり、囁きを聞いてしまうと狂ってしまうぞ！","ENG":"A non-Counter observing the hostile with their naked eyes or hearing its whispers will drive them insane!","TWN":"非制裁者的人類用肉眼觀測個體或聽到私語就會瘋掉！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"대장님!! 찾았습니다!!","JPN":"隊長！　見つかりました！！","ENG":"Commander!! We found him!!","TWN":"隊長！！找到了！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L1_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"숲 속에서 버넷 요원님을 찾았습니다.","JPN":"森の中で、エージェント・バーネットを見つけました。","ENG":"We found Agent Burnett in the forest.","TWN":"在樹林裡找到了伯內特特工。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"何だと……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이런 곳에서 혼자 뭘 하고 있는 거죠?","JPN":"こんなところで、一人で何をしているのですか？","ENG":"What are you doing here all alone?","TWN":"你一個人在這種地方幹什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"대답하세요, 물벼룩.","JPN":"答えなさい、ミジンコ。","ENG":"Answer me, Water Flea.","TWN":"回答我，水蚤。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신과 함께 이번 작전을 수행했던 기관원이 있을 겁니다.","JPN":"あなたと一緒に今回の作戦を遂行した機関員がいたでしょう。","ENG":"There was a member of the Institution whom you were accompanied by for this operation.","TWN":"有一個機關成員，和你一起執行過這次作戰。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"분명, 이곳의 좌표를 송신했던 사람이 있을 거예요. 그렇지 않나요?","JPN":"確か、ここの座標をあなたに送信した人がいたはずです。違いますか？","ENG":"There must have been someone who sent us the coordinates to this place. Is that not right?","TWN":"肯定有個人發送了這裡的座標，對不對？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……모건이야.","JPN":"……モーガンだ。","ENG":"...Morgan.","TWN":"……是摩根。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"기억해둬. 새디어스 모건.","JPN":"覚えておけよ。タデウス・モーガンを。","ENG":"Remember that name. Thaddeus Morgan.","TWN":"記住，薩迪烏斯·摩根。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……모건?","JPN":"……モーガン？","ENG":"...Morgan?","TWN":"……摩根？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"모건 할배가 그림자 도약으로 날 그곳에서 빼내줬어.","JPN":"モーガンのジジイが、影を通して俺をあそこから出してくれた。","ENG":"Morgan got me out of there using his shadow leap.","TWN":"摩根老頭用暗影躍遷把我從那裡弄出來了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"자기 목숨을 버려가면서까지 말이야.","JPN":"自分の命を捨ててまで。","ENG":"Sacrificing his own life in the process.","TWN":"甚至不惜犧牲自己的生命。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나한테는…… 나한테는 아버지 같은 사람이었는데…….","JPN":"俺には……俺にとっては、父親のような人だったのに……","ENG":"He... He was like a father to me...","TWN":"對我來說……對我來說他就像真正意義上的父親……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나는…… 성질만 부렸지, 단 한 번도 고맙다고 한 적 없는데…….","JPN":"俺は……いつも文句ばかり言って、一度もありがとうって伝えたこともなかったのに……","ENG":"And I... I only talked back to him, and I never got to thank him...","TWN":"我……就知道耍脾氣，從來沒對他說過謝謝……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이런 나를…… 자랑스럽다고 말해주던 사람이었는데……!","JPN":"こんな俺を……自慢だと言ってくれた人なのに……！","ENG":"He... used to say how he was proud of someone like me...!","TWN":"即使如此……他也還曾經跟我說以我為傲……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"학회가 부리는 잔해는 가아그셰블라의 파편으로 인해 생성되는 침식체.","JPN":"学会が操る残骸は、ガアグシェブラの破片によって生成される侵食体。","ENG":"The Remains that the Society controls are C.O.s that are created by the Fragments of Gha'agsheblah.","TWN":"學會使喚的殘骸是由加格舍夫拉的碎片產生的侵蝕體。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"인간이 잔해가 되어 버리면 <color=#ffd34c>정보 말소</color> 현상이 발생합니다.","JPN":"人間が残骸になってしまうと、<color=#ffd34c>情報の末梢</color>現象が発生します。","ENG":"When humans become the Remains, <color=#ffd34c>information erasure</color> occurs.","TWN":"當人類變成殘骸時，會出現<color=#ffd34c>資訊銷毀</color>的現象。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지식의 호수의 허수 에너지로 인해 존재 자체에 대한 정보 간섭이 일어나, 왜곡되며 소멸하고 말죠.","JPN":"知識の湖の虚数エネルギーによって存在自体に情報の干渉が生じ、歪曲され、消滅してしまう。","ENG":"The Imaginary Energy from the Lake of Knowledge interferes with the information of the entity, causing it to distort and disappear.","TWN":"因知識湖水的虛數能量特性，導致存在本身的資訊被干涉，被扭曲並銷毀。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 수없이 많은 기관원들은…… 자기 묘비조차도 존재하지 않아요.","JPN":"だから大勢の機関員には……墓碑すら存在しません。","ENG":"Which is why countless members of the Institution... don't even have their own grave.","TWN":"所以數不清的機關成員……都沒有自己的墓碑。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"생사는커녕, 그 존재 자체를 확인할 방도가 없기 때문입니다.","JPN":"生死はおろか、彼らの存在そのものを確かめるすべがないためです。","ENG":"We cannot confirm their status, much less their existence itself.","TWN":"別說是生死，甚至沒有確認其存在本身的方法。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 단 한 사람이라도.","JPN":"ですがたった一人でも。","ENG":"But, if one person.","TWN":"但是哪怕只有一個人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"우리 중 단 한 사람이라도, 그를 기억할 수 있다면 그는 죽은 게 아닙니다.","JPN":"私たちの中にたった一人でも、彼を覚えている人間がいるのなら、彼は死んだ訳ではありません。","ENG":"If one person among us can remember him, he is not truly gone.","TWN":"只要我們當中有一個人，能記住他，他就沒有死。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그는 프리드웬의 전설로서 우리 가슴 속에 영원히 남아 있을 거예요.","JPN":"彼はプリドウェンの伝説となって、私たちの中で永遠に生きていくでしょう。","ENG":"He will be with us in our hearts forever, as a legend of Prydwen.","TWN":"他作為普利多溫的傳說，將永遠留在我們的心中。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럴싸하게 포장하려고 해봤자 소용없어.","JPN":"それらしい言葉で飾る必要はない。","ENG":"You can sugarcoat it all you want, but it's no use.","TWN":"你別試圖為他說好話了，沒用的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"애초에 교수를 쫓겠다고 했을 때, 네 말대로 말렸어야 했어.","JPN":"教授を追いかけると言った時、お前のいう通りに止めるべきだった。","ENG":"You were right. We should've stopped him when he said he wanted to go after the Professor.","TWN":"當初他說要追教授的時候，就應該按你說的阻止他。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"적어도…….","JPN":"せめて……","ENG":"At least...","TWN":"至少……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그의 희생이 헛되지 않도록, 내가 성배를 끝장냈어야 했어.","JPN":"彼の犠牲が無駄にならないように、俺が聖杯を封印すべきだった。","ENG":"At the very least, I should've ended the Holy Grail, so that his sacrifice meant something.","TWN":"我本應該了結聖杯，免得他白白犧牲的。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"모건이 그렇게 되면서까지 수행하려고 했던 임무를…… 결국 내가 망쳐버린 거야.","JPN":"モーガンがあんな姿になっても成し遂げようとした任務を……俺が台無しにしてしまったんだ。","ENG":"But now... I've ruined the mission that Morgan tried so hard to complete, even in that state.","TWN":"摩根變成那副模樣也要完成的任務……結果還是被我搞砸了。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그 같잖은 정의감 때문에……!","JPN":"あんなどうでもいい正義感のせいで……！","ENG":"It was because of that useless justice of mine...!","TWN":"就因為那點不堪的正義感……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 할배가 죽은 건…… 전부 내 책임이라고!","JPN":"だから、ジジイが死んだのは……全部俺のせいなんだ！","ENG":"So... it's all my fault that he's dead!","TWN":"所以他的死……都是我的責任！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"착각하지 마세요, 물벼룩.","JPN":"勘違いしないでください、ミジンコ。","ENG":"Do not be mistaken, Water Flea.","TWN":"水蚤，別搞錯了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_9"},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관에 관한 모든 책임은 처음부터 끝까지 기관장인 저에게 있습니다.","JPN":"機関に関するすべての責任は、最初から最後まで機関長である私にあります。","ENG":"As Chief, I carry all the responsibility regarding the Institute.","TWN":"關於機關的所有責任，從頭到尾都在身為機關長的我身上。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_10"},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이 사태에 대해, 당신이 책임질 건 아무것도 없어요.","JPN":"この事態に対してあなたが責任を感じることなどなにもありません。","ENG":"You don't have to be responsible for anything that's currently happening.","TWN":"對於這件事情，你沒有什麼可負責的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_11"},{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 이곳을 떠나 꼴사납게 도망치든, 적에게 목숨을 구걸하든 마음대로 하세요.","JPN":"ですからここを離れて逃げ惑うなり、敵に命乞いするなり好きにしてください。","ENG":"So, you can do whatever you want. Run away with your tail between your legs, or go to the enemy and beg for mercy.","TWN":"所以，無論你是狼狽地從這裡跑開，還是搖著尾巴向敵人求饒，都隨你便。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_12"},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"홍차 폭탄……?","JPN":"紅茶爆弾……？","ENG":"Tea Bomb...?","TWN":"紅茶炸彈……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 그럼에도.","JPN":"ですが、それでも。","ENG":"But.","TWN":"但即便如此。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_13"},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼에도…… 당신이 저와 함께 마지막까지 싸우는 것을 선택한다면……!","JPN":"それでも……あなたが最後まで私と一緒に戦うことを選ぶのなら……！","ENG":"But if you still choose to fight by my side until the end...!","TWN":"即便如此……若你也選擇和我一起戰鬥到最後……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_14"},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"일어나서, 그 방패를 드세요.","JPN":"立ち上がり、盾を手に取りなさい。","ENG":"Stand, and hold that shield up.","TWN":"那就給我站起來，拿起那個盾牌。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_15"},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"방패를 짊어지고, 자신의 선택을 관철하세요.","JPN":"盾を背負って、自分の選んだ道を貫きなさい。","ENG":"Bear the weight of the shield and see your decision through.","TWN":"背上它，貫徹自己的選擇。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_16"},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그것이 제가 당신에게 부여할 수 있는 유일한 책무입니다.","JPN":"それが私があなたに与えられる、唯一の責務です。","ENG":"That is the only duty I can assign you.","TWN":"那是我唯一能賦予你的職責。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_17"},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저 역시 기관장으로서…… 제게 주어진 책임을 회피하지 않을 테니까요, 로이 버넷.","JPN":"私もまた機関長として……与えられた責任を全うします、ロイ・バーネット。","ENG":"And, as Chief... I won't shirk my responsibility either, Roy Burnett.","TWN":"我身為機關長……不會逃避賦予給我的責任，羅伊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_BD_ELIZABETH_IN_TRAILER_18"}]`);export{e as default};